// src/context/AuthContext.js
import React, { createContext, useState, useContext, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import authService from '../services/authService';

const AuthContext = createContext();

export const useAuth = () => {
    const context = useContext(AuthContext);
    if (!context) {
        throw new Error('useAuth must be used within an AuthProvider');
    }
    return context;
};

export const AuthProvider = ({ children }) => {
    const [user, setUser] = useState(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);
    const navigate = useNavigate();

    useEffect(() => {
        checkUser();
    }, []);

    const checkUser = () => {
        const currentUser = authService.getCurrentUser();
        setUser(currentUser);
        setLoading(false);
    };

    const login = async (username, password, useFingerprint = false, fingerprintId = null) => {
        setLoading(true);
        setError(null);
        try {
            let response;
            if (useFingerprint) {
                // Pass the fingerprint ID to the service
                response = await authService.loginWithFingerprint(username, fingerprintId);
            } else {
                response = await authService.loginWithPassword(username, password);
            }
            
            if (response.success) {
                setUser(response.user);
                // Store user info
                localStorage.setItem('user', JSON.stringify(response.user));
                // Redirect based on role
                if (response.user.role === 'master_admin') {
                    navigate('/admin');
                } else {
                    navigate('/dashboard');
                }
                return { success: true };
            } else {
                setError(response.error);
                return { success: false, error: response.error };
            }
        } catch (err) {
            setError(err.message);
            return { success: false, error: err.message };
        } finally {
            setLoading(false);
        }
    };

    const register = async (userData) => {
        setLoading(true);
        setError(null);
        try {
            const response = await authService.register(userData);
            if (response.success) {
                navigate('/login?registered=true');
                return { success: true };
            }
            return response;
        } catch (err) {
            setError(err.message);
            return { success: false, error: err.message };
        } finally {
            setLoading(false);
        }
    };

    const logout = () => {
        authService.logout();
        setUser(null);
        localStorage.removeItem('user');
        navigate('/');
    };

    const value = {
        user,
        loading,
        error,
        login,
        register,
        logout
    };

    return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
};
